"use client";

import { useState } from "react";
import Link from "next/link";
import {
  ArrowLeft,
  ClipboardCheck,
  FileText,
  CheckCircle,
  X,
  AlertTriangle,
  Search,
  Download,
  Eye,
  DollarSign,
  Calendar,
  User,
  Building2,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  CORES_TRT,
  FATURAS_TRT,
  CHECKLIST_AUDITORIA,
  SERVIDORES_TRT,
  CREDENCIADOS_TRT,
} from "@/lib/dados-trt-8a-regiao";

export default function AreaAuditoriaTRT() {
  type FaturaTipo = {
    id: string;
    numero_fatura: string;
    status: string;
    valor_bruto: number;
    valor_liquido: number;
    pdf_categoria: string;
    mes_referencia: number;
    ano_referencia: number;
    procedimento_id: string;
    credenciado_id: string;
    motivo_glosa: string | null;
    observacoes_auditoria?: string | null;
    nome_credenciado?: string;
    xml_arquivo?: string;
    pdf_arquivo?: string;
    auditor_id?: string | null;
  };
  const [faturas, setFaturas] = useState<FaturaTipo[]>(FATURAS_TRT.map(f => ({...f})));
  const [faturaSelecionada, setFaturaSelecionada] = useState<FaturaTipo | null>(null);
  const [checklist, setChecklist] = useState<{id: number; item: string; verificado: boolean; obrigatorio: boolean}[]>(
    CHECKLIST_AUDITORIA.map(item => ({...item}))
  );
  const [observacoes, setObservacoes] = useState("");
  const [motivoGlosa, setMotivoGlosa] = useState("");

  const toggleChecklistItem = (id: number) => {
    setChecklist((prev) =>
      prev.map((item) => (item.id === id ? { ...item, verificado: !item.verificado } : item))
    );
  };

  const aprovarFatura = () => {
    if (faturaSelecionada) {
      setFaturas((prev) =>
        prev.map((f) => (f.id === faturaSelecionada.id ? { ...f, status: "Aprovada" } : f))
      );
      setFaturaSelecionada(null);
      alert("Fatura aprovada com sucesso!");
    }
  };

  const glosarFatura = () => {
    if (faturaSelecionada && motivoGlosa) {
      setFaturas((prev) =>
        prev.map((f) =>
          f.id === faturaSelecionada.id
            ? { ...f, status: "Glosada", motivo_glosa: motivoGlosa }
            : f
        )
      );
      setFaturaSelecionada(null);
      setMotivoGlosa("");
      alert("Fatura glosada com sucesso!");
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "Pendente":
        return <Badge variant="secondary">Pendente</Badge>;
      case "Inserida":
        return (
          <Badge style={{ backgroundColor: CORES_TRT.info, color: "white" }}>Inserida</Badge>
        );
      case "Auditada":
        return (
          <Badge style={{ backgroundColor: CORES_TRT.terciaria, color: "white" }}>Auditada</Badge>
        );
      case "Aprovada":
        return <Badge style={{ backgroundColor: CORES_TRT.sucesso }}>Aprovada</Badge>;
      case "Glosada":
        return <Badge style={{ backgroundColor: CORES_TRT.alerta }}>Glosada</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  const itensPendentes = checklist.filter((item) => !item.verificado && item.obrigatorio).length;
  const itensVerificados = checklist.filter((item) => item.verificado).length;
  const progresso = (itensVerificados / checklist.length) * 100;

  return (
    <main className="min-h-screen" style={{ backgroundColor: CORES_TRT.fundo }}>
      {/* Header */}
      <header
        className="text-white shadow-lg"
        style={{
          background: `linear-gradient(135deg, ${CORES_TRT.primaria} 0%, ${CORES_TRT.secundaria} 100%)`,
        }}
      >
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/trt">
                <Button variant="ghost" size="icon" className="text-white hover:bg-white/20">
                  <ArrowLeft className="h-5 w-5" />
                </Button>
              </Link>
              <div className="flex items-center gap-3">
                <div className="p-2 bg-white/20 rounded-full">
                  <ClipboardCheck className="h-6 w-6" />
                </div>
                <div>
                  <h1 className="text-xl font-bold">Auditoria TIS</h1>
                  <p className="text-sm opacity-90">Análise de Conformidade</p>
                </div>
              </div>
            </div>
            <Badge variant="secondary" className="bg-white/20 text-white border-0">
              Acesso TIS/TRT
            </Badge>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-6">
        {/* Estatísticas */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
          <Card className="border-l-4" style={{ borderLeftColor: CORES_TRT.alerta }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Pendentes</p>
                  <p className="text-2xl font-bold" style={{ color: CORES_TRT.primaria }}>
                    {faturas.filter((f) => f.status === "Pendente" || f.status === "Inserida").length}
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_TRT.alerta}20` }}>
                  <AlertTriangle className="h-6 w-6" style={{ color: CORES_TRT.alerta }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_TRT.info }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Em Análise</p>
                  <p className="text-2xl font-bold" style={{ color: CORES_TRT.primaria }}>
                    {faturas.filter((f) => f.status === "Auditada").length}
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_TRT.info}20` }}>
                  <ClipboardCheck className="h-6 w-6" style={{ color: CORES_TRT.info }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_TRT.sucesso }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Aprovadas</p>
                  <p className="text-2xl font-bold" style={{ color: CORES_TRT.primaria }}>
                    {faturas.filter((f) => f.status === "Aprovada").length}
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_TRT.sucesso}20` }}>
                  <CheckCircle className="h-6 w-6" style={{ color: CORES_TRT.sucesso }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_TRT.destaque }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Glosadas</p>
                  <p className="text-2xl font-bold" style={{ color: CORES_TRT.primaria }}>
                    {faturas.filter((f) => f.status === "Glosada").length}
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_TRT.destaque}20` }}>
                  <X className="h-6 w-6" style={{ color: CORES_TRT.destaque }} />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Layout Principal */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Lista de Faturas */}
          <div className="lg:col-span-1">
            <Card className="h-full">
              <CardHeader>
                <CardTitle className="text-base flex items-center gap-2" style={{ color: CORES_TRT.primaria }}>
                  <Search className="h-4 w-4" />
                  Faturas Pendentes
                </CardTitle>
              </CardHeader>
              <CardContent className="p-0">
                <div className="divide-y max-h-[600px] overflow-y-auto">
                  {faturas.map((fatura) => {
                    const servidor = SERVIDORES_TRT.find((s) =>
                      FATURAS_TRT.find((f) => f.id === fatura.id)?.procedimento_id?.includes(s.matricula)
                    ) as {matricula: string; nome: string; cpf: string; data_nascimento: string; email: string; telefone: string; cargo: string; secretaria: string; lotacao: string; numero_guia: string; titular: boolean} | undefined;
                    const credenciado = CREDENCIADOS_TRT.find((c) => c.id === fatura.credenciado_id) as {id: string; cnpj: string; razao_social: string; nome_fantasia: string; tipo_prestador: string; endereco: string; cidade: string; estado: string; telefone: string; email: string; responsavel_tecnico: string; data_credenciamento: string; status: string; especialidades: string[]; avaliacao: number} | undefined;

                    return (
                      <div
                        key={fatura.id}
                        className={`p-4 cursor-pointer hover:bg-slate-50 transition-colors ${
                          faturaSelecionada?.id === fatura.id ? "bg-blue-50 border-l-4 border-blue-500" : ""
                        }`}
                        onClick={() => setFaturaSelecionada(fatura)}
                      >
                        <div className="flex items-start justify-between mb-2">
                          <span className="font-semibold text-sm">{fatura.numero_fatura}</span>
                          {getStatusBadge(fatura.status)}
                        </div>
                        <p className="text-xs text-slate-600 mb-1">
                          <User className="h-3 w-3 inline mr-1" />
                          {servidor?.nome || "Servidor não encontrado"}
                        </p>
                        <p className="text-xs text-slate-600 mb-2">
                          <Building2 className="h-3 w-3 inline mr-1" />
                          {credenciado?.nome_fantasia || credenciado?.razao_social}
                        </p>
                        <div className="flex items-center justify-between">
                          <span className="text-sm font-medium" style={{ color: CORES_TRT.primaria }}>
                            R$ {fatura.valor_bruto.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                          </span>
                          <span className="text-xs text-slate-500">
                            <Calendar className="h-3 w-3 inline mr-1" />
                            {fatura.mes_referencia}/{fatura.ano_referencia}
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Área de Auditoria */}
          <div className="lg:col-span-2">
            {faturaSelecionada ? (
              <Card className="h-full">
                <CardHeader className="border-b">
                  <div className="flex items-center justify-between">
                    <CardTitle style={{ color: CORES_TRT.primaria }}>
                      Auditoria: {faturaSelecionada.numero_fatura}
                    </CardTitle>
                    <div className="flex gap-2">
                      <Button variant="outline" size="sm">
                        <Eye className="h-4 w-4 mr-1" />
                        Ver XML
                      </Button>
                      <Button variant="outline" size="sm">
                        <Download className="h-4 w-4 mr-1" />
                        PDF
                      </Button>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="p-6 space-y-6">
                  {/* Dados da Fatura */}
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="p-3 bg-slate-50 rounded-lg">
                      <p className="text-xs text-slate-500">Valor Bruto</p>
                      <p className="font-bold text-lg">
                        R${" "}
                        {faturaSelecionada.valor_bruto.toLocaleString("pt-BR", {
                          minimumFractionDigits: 2,
                        })}
                      </p>
                    </div>
                    <div className="p-3 bg-slate-50 rounded-lg">
                      <p className="text-xs text-slate-500">Valor Líquido</p>
                      <p className="font-bold text-lg" style={{ color: CORES_TRT.terciaria }}>
                        R${" "}
                        {faturaSelecionada.valor_liquido.toLocaleString("pt-BR", {
                          minimumFractionDigits: 2,
                        })}
                      </p>
                    </div>
                    <div className="p-3 bg-slate-50 rounded-lg">
                      <p className="text-xs text-slate-500">Categoria</p>
                      <p className="font-bold">{faturaSelecionada.pdf_categoria}</p>
                    </div>
                    <div className="p-3 bg-slate-50 rounded-lg">
                      <p className="text-xs text-slate-500">Status</p>
                      {getStatusBadge(faturaSelecionada.status)}
                    </div>
                  </div>

                  {/* Checklist */}
                  <div>
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="font-semibold" style={{ color: CORES_TRT.primaria }}>
                        Checklist de Conformidade
                      </h3>
                      <div className="flex items-center gap-2">
                        <div
                          className="h-2 w-32 bg-slate-200 rounded-full overflow-hidden"
                          style={{ backgroundColor: `${CORES_TRT.sucesso}30` }}
                        >
                          <div
                            className="h-full transition-all"
                            style={{
                              width: `${progresso}%`,
                              backgroundColor: progresso === 100 ? CORES_TRT.sucesso : CORES_TRT.info,
                            }}
                          />
                        </div>
                        <span className="text-sm text-slate-600">{Math.round(progresso)}%</span>
                      </div>
                    </div>

                    {itensPendentes > 0 && (
                      <div className="mb-4 p-3 bg-amber-50 rounded-lg border border-amber-200">
                        <p className="text-sm text-amber-800">
                          <AlertTriangle className="h-4 w-4 inline mr-1" />
                          Atenção: {itensPendentes} item(ns) obrigatório(s) pendente(s)
                        </p>
                      </div>
                    )}

                    <div className="space-y-2">
                      {checklist.map((item) => (
                        <div
                          key={item.id}
                          className={`flex items-start gap-3 p-3 rounded-lg border ${
                            item.verificado
                              ? "bg-green-50 border-green-200"
                              : item.obrigatorio
                              ? "bg-white border-slate-200"
                              : "bg-slate-50 border-slate-200"
                          }`}
                        >
                          <Checkbox
                            id={`check-${item.id}`}
                            checked={item.verificado}
                            onCheckedChange={() => toggleChecklistItem(item.id)}
                          />
                          <div className="flex-1">
                            <label
                              htmlFor={`check-${item.id}`}
                              className={`text-sm cursor-pointer ${
                                item.verificado ? "line-through text-slate-500" : "text-slate-900"
                              }`}
                            >
                              {item.item}
                            </label>
                            {item.obrigatorio && !item.verificado && (
                              <Badge
                                variant="outline"
                                className="ml-2 text-xs"
                                style={{ borderColor: CORES_TRT.alerta, color: CORES_TRT.alerta }}
                              >
                                Obrigatório
                              </Badge>
                            )}
                          </div>
                          {item.verificado && (
                            <CheckCircle className="h-5 w-5" style={{ color: CORES_TRT.sucesso }} />
                          )}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Observações */}
                  <div>
                    <label className="block text-sm font-medium mb-2" style={{ color: CORES_TRT.primaria }}>
                      Observações da Auditoria
                    </label>
                    <textarea
                      className="w-full p-3 border rounded-lg text-sm min-h-[100px]"
                      placeholder="Digite suas observações sobre a fatura..."
                      value={observacoes}
                      onChange={(e) => setObservacoes(e.target.value)}
                    />
                  </div>

                  {/* Motivo da Glosa (se aplicável) */}
                  {faturaSelecionada.status === "Glosada" && (
                    <div className="p-4 bg-red-50 rounded-lg border border-red-200">
                      <label className="block text-sm font-medium mb-2 text-red-700">
                        Motivo da Glosa
                      </label>
                      <Input
                        placeholder="Informe o motivo da glosa..."
                        value={motivoGlosa}
                        onChange={(e) => setMotivoGlosa(e.target.value)}
                        className="border-red-300"
                      />
                    </div>
                  )}

                  {/* Botões de Ação */}
                  <div className="flex gap-3 pt-4 border-t">
                    <Button
                      className="flex-1"
                      size="lg"
                      onClick={aprovarFatura}
                      disabled={itensPendentes > 0}
                      style={{
                        backgroundColor: itensPendentes > 0 ? "#ccc" : CORES_TRT.sucesso,
                      }}
                    >
                      <CheckCircle className="h-4 w-4 mr-2" />
                      Aprovar Fatura
                    </Button>
                    <Button
                      className="flex-1"
                      size="lg"
                      variant="outline"
                      onClick={() => setFaturaSelecionada(null)}
                    >
                      Cancelar
                    </Button>
                    <Button
                      className="flex-1"
                      size="lg"
                      variant="destructive"
                      onClick={glosarFatura}
                      disabled={!motivoGlosa}
                    >
                      <X className="h-4 w-4 mr-2" />
                      Glosar
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ) : (
              <Card className="h-full flex items-center justify-center">
                <CardContent className="text-center py-12">
                  <ClipboardCheck className="h-16 w-16 mx-auto mb-4 opacity-30" style={{ color: CORES_TRT.primaria }} />
                  <h3 className="text-lg font-semibold text-slate-600">Selecione uma fatura</h3>
                  <p className="text-sm text-slate-500">
                    Clique em uma fatura da lista à esquerda para iniciar a auditoria
                  </p>
                </CardContent>
              </Card>
            )}
          </div>
        </div>

        {/* Footer */}
        <footer className="mt-8 pt-6 border-t text-center text-sm text-slate-500">
          <p style={{ color: CORES_TRT.primaria }}>TRT 8ª Região - Sistema de Auditoria TIS</p>
          <p>Acesso restrito a auditores autorizados</p>
        </footer>
      </div>
    </main>
  );
}
